#include<bits/stdc++.h>
using namespace std;
long long a[100010],sum[100010],dp[100010],lst[100010];
struct segment_tree
{
    struct node
    {
        long long l,r,min1;
        long long lson,rson;
    }a[300010];
    long long cnt;
    segment_tree():cnt(0){}
    void pushup(long long x)
    {
        a[x].min1=min(a[a[x].lson].min1,a[a[x].rson].min1);
    }
    long long init(long long l,long long r)
    {
        long long x=++cnt,mid=(l+r)>>1;
        a[x].l=l;
        a[x].r=r;
        if(l==r)
        {
            a[x].min1=1e18;
            return x;
        }
        a[x].lson=init(l,mid);
        a[x].rson=init(mid+1,r);
        pushup(x);
        return x;
    }
    void update(long long x,long long p,long long z)
    {
        if(a[x].l>p||a[x].r<p)
        {
            return;
        }
        if(a[x].l==a[x].r)
        {
            a[x].min1=z;
            return;
        }
        update(a[x].lson,p,z);
        update(a[x].rson,p,z);
        pushup(x);
    }
    long long getmin(long long x,long long l,long long r)
    {
        if(l==0)
        {
            l=1;
        }
        if(l>r||a[x].l>r||a[x].r<l)
        {
            return 1e18;
        }
        if(a[x].l>=l&&a[x].r<=r)
        {
            return a[x].min1;
        }
        return min(getmin(a[x].lson,l,r),getmin(a[x].rson,l,r));
    }
}t;
int main()
{
    long long n,m;
    scanf("%lld%lld",&n,&m);
    t.init(1,n+1);
    stack<long long> s;
    for(long long i=1;i<=n;i++)
    {
        scanf("%lld",&a[i]);
        sum[i]=sum[i-1]+a[i];
        while(!s.empty()&&a[s.top()]<=a[i])
        {
            s.pop();
        }
        if(!s.empty())
        {
            lst[i]=s.top();
        }
        s.push(i);
    }
    dp[0]=0;
    t.update(1,1,0);
    for(long long i=1;i<=n;i++)
    {
        dp[i]=1e18;
        long long p=lower_bound(sum,sum+1+n,sum[i]-m)-sum+1;//s[i]-s[j-1]<=m->s[j-1]>=s[i]-m
        long long max1=0,sum=0;
        for(long long j=i;j>=1;)
        {
            long long l=max(p,lst[j]+1),r=j;
            max1=max(max1,a[j]);
            dp[i]=min(dp[i],t.getmin(1,l,r)+max1);
            j=lst[j];
        }
        t.update(1,i+1,dp[i]);
    }
    printf("%lld",dp[n]);
    return 0;
}
